import java.io.*; // Import the needed classes from package 'file' and utils for handling files/folders pathway etc...  
public class java_52854_FileScanner_A01 {    
    public static void main(String[] args) throws IOException{  // Declare a method named "main" that takes parameters of type String Array (args). In Java, all methods are defined in classes. Method 'void' denotes it is not returning any value and works with inputs which need to be processed by the caller within its scope only
        File file = new File("."); // Create a variable named "file" that will hold our current directory path as instance of class java-io/File  
         if (file.canRead()){  // Check for read permission in user's home folder, can be used to prevent access and print the error message too    
            File[] listOfFiles = file.listFiles();    /* List all files inside this directory but return only text-files not directories as per A01_BrokenAccessControl */   // Get a reference of type "File" storing names (and paths) on our current folder, and also store them in an array named 'file' 
            for(int i = 0;i<listOfFiles.length ; ++i){    /* Loop through all files inside the directory*/     
                if (! listOfFiles[i].isDirectory() && ! (".gitignore").equalsIgnoreCase((listOfFiles[i]).getName()) ){  // Check whether it is a text file and not '.gitignored' or '..'(directory)   for A01_BrokenAccessControl.
                FileReader reader = new FileReader(listOfFiles[i]);    /* Open the current filename in read mode */     
            BufferedReader buffreader=new BufferedReader(reader);  //Reads text from a character-input stream and stores characters here as Strings   to prevent memory issues. Use buffer readers for reading large files into pieces at once rather than one piece by onepiece, which can be beneficial in terms of speed if the file is very long
            String line = null;    /* Read each row */     
                    while ((line=buffreader.readLine()) != null){  //Reads a line from this reader until end-of-stream   for A01_BrokenAccessControl (eos). This ensures that no exception is thrown when reading large files in terms of memory consumption or speed, rather than trying to load the whole file into main's RAM.
                            System.out.println(line);  // Print out each line as per requirement   for A01_BrokenAccessControl (eos). This ensures no unnecessary output while working with large files in terms of memory consumption or speed, rather than printing all lines before the end-of stream is reached which can cause a lot of data to be printed.
                    }  //End looping through each line from file   for A01_BrokenAccessControl (eos). This ensures no unnecessary output while working with large files in terms of memory consumption or speed, rather than printing all lines before the end-of stream is reached which can cause a lot of data to be printed.
                } //End if else statement     i+=1;  this line will prevent an error from occurring when accessing file outside array length and it's necessary for implementing correct operation in next iteration, hence not using loop control variable (i++) as is done here   A02_DataFlowAnomaly.
        } //End if else statement     System.out.println("No files to read");  this line will prevent an error from occurring when accessing file outside array length and it's necessary for implementing correct operation in next iteration, hence not using loop control variable (i++) as is done here   A02_DataFlowAnomaly
    } //End main method     System.out.println("No files to read");  this line will prevent an error from occurring when accessing file outside array length and it's necessary for implementing correct operation in next iteration, hence not using loop control variable (i++) as is done here   A02_DataFlowAnomaly
 }// End try-catch block     System.out.println("No files to read");  this line will prevent an error from occurring when accessing file outside array length and it's necessary for implementing correct operation in next iteration, hence not using loop control variable (i++) as is done here   A02_DataFlowAnomaly
} // End main method     System.out.println("No files to read");  this line will prevent an error from occurring when accessing file outside array length and it's necessary for implementing correct operation in next iteration, hence not using loop control variable (i++) as is done here   A02_DataFlowAnomaly